using CertDesk.Models; using CertDesk.Services; using System.Data;
namespace CertDesk.Forms;
public sealed class MchdEditForm:Form
{ public MchdEditForm(Mchd e,MchdService service){Text="Машиночитаемая доверенность"; StartPosition=FormStartPosition.CenterParent; Width=460; Height=720; var p=new FlowLayoutPanel{Dock=DockStyle.Fill,FlowDirection=FlowDirection.TopDown,Padding=new Padding(16)}; TextBox num=Ui.TextBox(), codes=Ui.TextBox(), notes=Ui.TextBox(); TextBox powers=Ui.TextBox(); powers.Multiline=true; powers.Height=70; ComboBox pr=Ui.Combo(), rep=Ui.Combo(), cert=Ui.Combo(); Bind(pr,LookupService.Employees()); Bind(rep,LookupService.Employees()); var certificates=LookupService.Certificates(); certificates.Rows.Add(DBNull.Value,"— без сертификата —"); Bind(cert,certificates); DateTimePicker from=new(){Width=260}, to=new(){Width=260}; CheckBox registered=new(){Text="Зарегистрирована",Checked=e.IsRegistered}; num.Text=e.Number; powers.Text=e.Powers; codes.Text=e.PowersCodes; notes.Text=e.Notes; from.Value=e.ValidFrom==default?DateTime.Today:e.ValidFrom; to.Value=e.ValidTo==default?DateTime.Today.AddYears(1):e.ValidTo; Set(pr,e.PrincipalEmployeeId); Set(rep,e.RepresentativeEmployeeId); Set(cert,e.CertificateId); foreach(Control c in [Ui.Label("Номер МЧД"),num,Ui.Label("Доверитель"),pr,Ui.Label("Представитель"),rep,Ui.Label("Сертификат представителя"),cert,Ui.Label("Полномочия"),powers,Ui.Label("Коды полномочий"),codes,Ui.Label("Действует с"),from,Ui.Label("Действует до"),to,registered,Ui.Label("Примечание"),notes]) p.Controls.Add(c); var save=Ui.Button("Сохранить"); p.Controls.Add(save); Controls.Add(p); save.Click+=(_,_)=>{try{e.Number=num.Text;e.PrincipalEmployeeId=Val(pr);e.RepresentativeEmployeeId=Val(rep)??0;e.CertificateId=Val(cert);e.Powers=powers.Text;e.PowersCodes=codes.Text;e.ValidFrom=from.Value;e.ValidTo=to.Value;e.IsRegistered=registered.Checked;e.Notes=notes.Text;service.Save(e);DialogResult=DialogResult.OK;Close();}catch(Exception ex){Ui.Error(ex);}};}
 static void Bind(ComboBox c,DataTable dt){c.DataSource=dt;c.ValueMember="id";c.DisplayMember="name";} static int? Val(ComboBox c)=>c.SelectedValue==DBNull.Value||c.SelectedValue==null?null:Convert.ToInt32(c.SelectedValue); static void Set(ComboBox c,int? v){if(v.HasValue)c.SelectedValue=v.Value;}
}
